const NL = String.fromCharCode(10);
export const OFFICIAL_V88 = (() => {
  const m = new Map();
  for (const l of RAW.split(NL)) {
    if (!l) continue;
    const [s, dc, drc, dbc, w, d, h, cat, sub] = l.split('|');
    m.set(s, { dc: +dc || 0, drc: +drc || 0, dbc: +dbc || 0, w: +w || null, d: +d || null, h: +h || null, cat: cat || '', sub: sub || '' });
  }
  return m;
})();

